                                const char* ip_addr,
                                const char* netmask,
                                const char* gateway)
{
    static const char prefix_ip[] = "ip addr ";
    static const char prefix_netmask[] = " netmask ";
    static const char prefix_gateway[] = " gateway ";

    size_t required_len;

    if (cmd_buffer == NULL || ip_addr == NULL || netmask == NULL || gateway == NULL) {
        return -1;
    }

    if (buffer_size == 0) {
        return -1;
    }

    if (ip_addr[0] == '\0' || netmask[0] == '\0' || gateway[0] == '\0') {
        cmd_buffer[0] = '\0';
        return -1;
    }

    required_len = strlen(prefix_ip)
                 + strlen(ip_addr)
                 + strlen(prefix_netmask)
                 + strlen(netmask)
                 + strlen(prefix_gateway)
                 + strlen(gateway)
                 + 1; /* null terminator */

    if (required_len > buffer_size) {
        cmd_buffer[0] = '\0';
        return -1;
    }

    cmd_buffer[0] = '\0';

    strcat(cmd_buffer, prefix_ip);
    strcat(cmd_buffer, ip_addr);
    strcat(cmd_buffer, prefix_netmask);
    strcat(cmd_buffer, netmask);
    strcat(cmd_buffer, prefix_gateway);
    strcat(cmd_buffer, gateway);

    return 0;
}
